use super::*;

fn png_to_rgba(png_bytes: &[u8]) -> Vec<u8> {
    let decoder = png::Decoder::new(std::io::Cursor::new(png_bytes));
    let mut reader = decoder.read_info().expect("valid PNG header");
    let buf_size = reader.output_buffer_size().expect("output buffer size");
    let mut buf = vec![0u8; buf_size];
    reader.next_frame(&mut buf).expect("PNG frame decode");
    buf
}

#[test]
fn test_icon_render_digits_0_to_9() {
    let cases: &[(&str, &[u8; 1024])] = &[
        ("1", &EXPECTED_1),
        ("2", &EXPECTED_2),
        ("3", &EXPECTED_3),
        ("4", &EXPECTED_4),
        ("5", &EXPECTED_5),
        ("6", &EXPECTED_6),
        ("7", &EXPECTED_7),
        ("8", &EXPECTED_8),
        ("9", &EXPECTED_9),
        ("0", &EXPECTED_ZERO),
    ];
    for &(name, expected) in cases {
        let png = render_icon_png_from_name(name);
        let pixels = png_to_rgba(&png);
        assert_eq!(pixels.as_slice(), expected.as_slice(), "pixel mismatch for icon '{name}'");
    }
}

